{
  "name": "Texas Simplified Application Project (TSAP) for SNAP",
  "eligibility": {
    "age": 60,
    "income_limits": "TSAP uses SNAP eligibility rules, which include gross monthly income limits varying by household size (e.g., for October 1, 2025–September 30, 2026: 1 person $1,634, 2 people $2,210, 3 people $2,786; full table available via official SNAP resources). Seniors over 60 and disabled individuals have simplified broad-based categorical eligibility with no separate asset test.",
    "asset_limits": "No asset limits or test apply under TSAP's simplified broad-based categorical eligibility; primary residence, one vehicle, and most household goods are exempt under standard SNAP rules for this group.",
    "other_requirements": ["Texas resident", "U.S. citizen or qualified non-citizen", "Meets SNAP income and categorical requirements (age 60+ or disabled)", "Intended for seniors over 60 and Texans with disabilities"]
  },
  "benefits": {
    "type": "financial",
    "value": "SNAP (Supplemental Nutrition Assistance Program) food benefits loaded monthly on an Electronic Benefits Transfer (EBT) card for purchasing eligible groceries; benefit amounts vary by income, household size, and expenses (e.g., average $200–$300/month per person, calculated individually).",
    "varies_by": "household_size"
  },
  "application": {
    "methods": [
      "Phone: Call 844-583-1500 to reach a local TSAP assister anywhere in Texas",
      "Online: YourTexasBenefits.com prescreening tool and application",
      "In-person or mail via local Texas Health and Human Services office (find via 844-583-1500)"
    ],
    "processing_time": "Standard SNAP processing: 30 days for most applicants; expedited up to 7 days if very low income/no assets.",
    "waitlist": null,
    "forms": ["Your Texas Benefits online application", "SNAP application form 3200-318 (accessible via YourTexasBenefits.com)"],
    "documents": ["Proof of age (ID, birth certificate)", "Proof of income (pay stubs, SSI award letter)", "Proof of disability if applicable (doctor's note, SSDI letter)", "Rent/mortgage/utility bills for deductions", "ID and Social Security number"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Assisters vary by area (local providers reached via 844-583-1500); processing times may differ slightly by local HHS office workload.",
    "offices_or_providers": ["Local Texas Health and Human Services offices; TSAP assisters statewide via phone"]
  },
  "official_source": "https://www.hhs.texas.gov/services/food/snap-food-benefits/texas-simplified-application-project-tsap-snap-food-benefits",
  "gotchas": [
    "TSAP is a simplified application process for standard SNAP benefits, not a separate program with unique benefits—expect regular SNAP rules on recertification every 6–12 months.",
    "Income limits follow annual SNAP adjustments; verify current figures as they change October 1.",
    "Disabled applicants under 60 qualify if they meet disability criteria, but must be 60+ for pure senior eligibility.",
    "No separate asset test, but must still report countable resources if questioned.",
    "Benefits are for food only; EBT card cannot be used for hot foods or non-grocery items."
  ],
  "data_shape_notes": "Simplified process eliminates asset test for seniors 60+ and disabled; eligibility tied to standard SNAP with household-size varying income limits and benefits; statewide with local assisters."
}

{
  "name": "Texas State Health Insurance Assistance Program (SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income or asset limits; open to all Medicare-eligible individuals, their families, and caregivers, including those with limited incomes, under age 65 with disabilities, or dually eligible for Medicare and Medicaid[1][2][3]",
    "asset_limits": "No asset limits or tests apply[2][3]",
    "other_requirements": ["Must be Medicare-eligible (typically age 65+ or under 65 with certain disabilities)", "Available to Medicare beneficiaries, families, and caregivers[1][2][3]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free one-on-one counseling and assistance on Medicare options (Parts A, B, C, D, Medigap), prescription drug plans, applying for Medicare Savings Programs (MSP), Low-Income Subsidy (Extra Help/LIS), Medicaid; group presentations, outreach events, fraud prevention via Senior Medicare Patrol (SMP); provided in-person, by phone, media[1][2][3][4][7]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-800-252-9240[7]", "Website: Texas Health Information, Counseling, and Advocacy Program (HICAP) site (linked via shiphelp.org/ships/texas/)[7]", "In-person or local counseling via community-based networks (contact phone for local sites)[1][2][7]"],
    "processing_time": "No formal application or processing time; services provided upon contact with counselors[2][3]",
    "waitlist": null,
    "forms": ["No specific forms required for SHIP counseling; counselors assist with applications for MSP, LIS, or other benefits[2][3]"],
    "documents": ["Medicare card, current health/prescription drug plan details, income info if applying for savings programs (counselors guide preparation)[2][3]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available statewide to Medicare-eligible residents[1][7]",
    "regional_variations": "Delivered through local community-based networks, agencies, and providers; specific offices/counselors vary by region but services standardized[1][2][5]",
    "offices_or_providers": ["Local sites coordinated via 1-800-252-9240; over 2,200 national sites including Texas[2]"]
  },
  "official_source": "https://www.shiphelp.org/ships/texas/ (Texas SHIP page); program managed by Texas Health Information, Counseling, and Advocacy Program (HICAP)[7]",
  "gotchas": ["Not direct financial aid or healthcare—only free counseling/advocacy; no enrollment on your behalf, but guides you; Texas calls it HICAP (not always listed as SHIP); often paired with SMP for fraud help; states have flexibility, so confirm Texas details via phone[2][3][6][7]", "People miss that it's volunteer/staff-based with no cost or eligibility barriers beyond Medicare[1][3]"],
  "data_shape_notes": "no income/asset test; counseling-only service via statewide local networks; named HICAP in Texas; immediate access, no waitlist or application[1][2][7]"
}

{
  "name": "Family Caregiver Support Program",
  "eligibility": {
    "age": null,
    "income_limits": "No specific income limits or tables identified for this program in Texas; related programs like Medicaid waivers (e.g., STAR+PLUS) have varying income maximums based on household size and waiver type, but require Medicaid eligibility with financial and medical assessments. Caregivers in DFPS-related assistance cannot exceed 300% of federal poverty guidelines for cash aid.",
    "asset_limits": "No asset limits specified for this program; HCBS waivers do not have strict $2,000 nonexempt asset max like LTC Medicaid, but financial eligibility is assessed.",
    "other_requirements": ["Care recipient typically must be elderly (60+ implied for aging programs), Texas resident, need daily assistance or nursing home level care, and enrolled in Medicaid for paid family caregiving options like STAR+PLUS; family caregiver must be non-spouse relative or friend meeting training/background requirements."]
  },
  "benefits": {
    "type": "service",
    "value": "Specific services not detailed; related programs provide in-home personal care, respite, training, and potential paid caregiving at minimum wage (hours vary, not guaranteed 40/week); STAR+PLUS offers long-term home care with family as paid attendants.",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Phone: 2-1-1 (Texas Health and Human Services)", "Website: YourTexasBenefits.com", "Contact local Area Agency on Aging via Council of Governments region", "In-person: Local Area Agency on Aging offices"],
    "processing_time": "Not specified",
    "waitlist": "Possible regional waitlists due to demand, varies by waiver and area",
    "forms": ["No specific form names identified; applications through YourTexasBenefits.com or HHSC processes"],
    "documents": ["Proof of income, residency, medical needs assessment, Medicaid enrollment proof, caregiver background check"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Administered regionally through 24 Councils of Governments/Area Agencies on Aging; eligibility and services via Medicaid waivers may vary",
    "regional_variations": "Differs by Council of Governments region with local Area Agencies on Aging handling assessments, available waivers (e.g., STAR+PLUS, HCS, CFC), providers, and wait times",
    "offices_or_providers": ["Local Area Agency on Aging offices by county/Council of Governments region"]
  },
  "official_source": "https://www.hhs.texas.gov/services/aging/long-term-care/home-community-based-care",
  "gotchas": ["Not direct state payment to family caregivers without Medicaid waiver eligibility; spouse typically cannot be paid; requires nursing home level 'at need' medical assessment plus financial eligibility; hours/payment not guaranteed at desired levels (e.g., minimum wage, <40/week); confused with VA or DFPS programs; regional variations mean contacting local AAA essential; no automatic pay—must qualify loved one first."],
  "data_shape_notes": "Administered regionally via 24 Councils of Governments/Area Agencies on Aging; ties to Medicaid HCBS waivers like STAR+PLUS (no strict asset test, income varies); no standalone income/asset tables for core program; eligibility dual medical/financial with local assessment."
}

{
  "name": "Legal Aid for Seniors (via AAAs)",
  "eligibility": {
    "age": 60,
    "income_limits": "No strict financial criteria; income and resources may be considered to prioritize those with greatest economic or social needs, but services are available regardless[3][4].",
    "asset_limits": "No asset limits specified; prioritization based on economic need without formal cutoffs[3][4].",
    "other_requirements": ["Targeted to older individuals with economic or social needs", "Texas resident", "Civil legal matters only (e.g., benefits access, housing, guardianship)"]
  },
  "benefits": {
    "type": "service",
    "value": "Legal assistance including: access to public benefits (SSI/SSDI, Medicaid, Medicare, veterans benefits); drafting advance directives and surrogate decision makers; guardianship issues (focused on client representation); housing access and protection from eviction/foreclosure; long-term care financing options. Provided as nearly 1 million hours nationwide annually via ~1,000 providers[3].",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Contact local Area Agency on Aging (AAA) by finding your AAA via Texas Health and Human Services (search 'Texas AAAs' or texaslawhelp.org)", "Phone and in-person via 28 AAAs covering all 254 counties (specific numbers vary by region; e.g., via texaslawhelp.org/aaa)", "No specific statewide form; referrals through AAAs"],
    "processing_time": "Not specified in sources",
    "waitlist": null,
    "forms": [],
    "documents": ["Proof of age (e.g., ID showing 60+)", "Residency proof", "Income/resources info for prioritization (not required for eligibility)", "Details of legal issue"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available via 28 AAAs covering all 254 Texas counties; must contact local AAA[4].",
    "regional_variations": "Delivered through 28 regional AAAs with potential differences in providers, wait times, and prioritization; each AAA handles local delivery[4][5].",
    "offices_or_providers": ["28 Area Agencies on Aging (AAAs) across Texas; find via texaslawhelp.org/article/area-agencies-on-aging-a-place-to-get-help"]
  },
  "official_source": "https://acl.gov/programs/legal-help/legal-services-elderly-program",
  "gotchas": ["No financial eligibility barriers, but services prioritize greatest need—may not guarantee case acceptance[3][4]", "Civil matters only; not for criminal or personal injury[1]", "Must go through local AAA, not direct statewide application; find your AAA first[4]", "Even if eligible, organization may not take every case[2]"],
  "data_shape_notes": "No income/asset tests; delivered regionally via 28 AAAs; prioritized by economic/social need; restricted service reporting limits detailed tracking[4][5]"
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; services are free and available to any resident regardless of financial status[5][6]",
    "asset_limits": "No asset limits; no financial eligibility requirements[5][6]",
    "other_requirements": ["Must be a resident of a nursing facility or assisted living facility in Texas[5][6][8]", "Services also extend to certain caregivers and family members of persons 60 years or older[2]"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Advocacy for residents' rights including investigating and resolving complaints, representing resident perspectives on laws and policies, preventing abuse and neglect through education and support, ensuring freedom from abuse/restraints, privacy, access to records/inspections, notification of services/costs, protection from improper transfer/discharge, non-discrimination, grievance rights, personal/financial autonomy, and advance directives[1][5][6][8]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-800-252-2412[5][6]", "Website: https://ltco.texas.gov (find local ombudsman)[6]", "Email the state office[6]", "Contact local program (e.g., in-person visits to facilities by ombudsmen)[3][4]"],
    "processing_time": "Immediate assistance available upon contact; no formal application processing[5][6]",
    "waitlist": null,
    "forms": ["No specific application forms required for receiving services; program resolves complaints directly[2][6]"],
    "documents": ["No documents needed to request services; provide details of complaint or concern verbally or via contact[5][6]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to residents of nursing facilities and assisted living facilities; excludes state supported living centers (separate ombudsman) and non-LTC health/human services[6]",
    "regional_variations": "Administered locally by different agencies (e.g., Cizik School of Nursing in Harris County[3], The Senior Source in Dallas County[4], Texoma Council of Governments[5], East Texas AAA[8]); volunteer training and coverage may vary by local program but core services are consistent statewide[1][2][3][4][5]",
    "offices_or_providers": ["Local programs via https://ltco.texas.gov (find by area)[6]"]
  },
  "official_source": "https://ltco.texas.gov[6]",
  "gotchas": ["Not a direct service provider like healthcare or financial aid—purely advocacy and complaint resolution[1][6]", "Families often confuse with eligibility-based programs; no income/asset tests, but only for those already in LTC facilities[5][6]", "Volunteers must be 18+, pass background checks, complete training/internship, and avoid conflicts of interest (e.g., no licensing or care provision roles)—this is for becoming an ombudsman, not receiving services[1][2][3][7]", "Independent of facilities; cannot determine Medicaid eligibility or conduct PASRR[2]", "Complaints are confidential and impartial[1][6]"],
  "data_shape_notes": "no income test; advocacy-only for residents of nursing homes/assisted living facilities; free, confidential, statewide with local administration; not for volunteers or facility admission—focuses on rights protection inside facilities"
}

{
  "name": "Texas Aging and Disability Resource Centers (ADRCs)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; services provided without regard to income levels[1][3][5]",
    "asset_limits": "No asset limits or tests mentioned; access is free regardless of financial status[1][3][5]",
    "other_requirements": ["Serves older adults (typically 65+), people with disabilities of any age, family caregivers, veterans, and families with children with special needs; residency in Texas (all 254 counties)[1][2][3][4]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free personalized guidance, information and assistance, referrals to local services (in-home care, housing assistance, transportation, respite care), help navigating eligibility for state/federal programs, person-centered planning, service coordination, advocacy; no direct financial aid or fixed hours/dollars provided by ADRC itself[1][2][3][5]",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Statewide toll-free phone: 1-855-YES-ADRC (1-855-937-2372) - routed to local ADRC[1][3][4]", "Local ADRC phone (e.g., Heart of Texas: 254-292-1855)[3]", "In-person walk-ins at local ADRC offices[3][5]", "Online referrals or agency contact via local ADRC websites (e.g., atcog.org/adrc, wctcog.org/adrc)[1][5]"],
    "processing_time": "Immediate guidance and referrals upon contact; no specified processing time as it's information/referral service[3][5]",
    "waitlist": null,
    "forms": ["No specific universal forms; assistance provided in completing applications for referred programs[5]"],
    "documents": ["No documents required for initial ADRC contact; prepare personal details (needs, location) for referrals; specific docs depend on referred services[3][5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Serves all 254 Texas counties via 28 designated ADRCs operated by local councils/agencies[2][3][4]",
    "regional_variations": "28 regional ADRCs with local providers, phone numbers, and specific referral networks (e.g., Ark-Tex, Heart of Texas, West Central Texas, North Central Texas); services routed by location[1][3][5]",
    "offices_or_providers": ["Examples: Ark-Tex (atcog.org), Heart of Texas (hotcogtx.gov, 254-292-1855), West Central Texas (wctcog.org), North Central Texas (nctadrc.org), Tarrant County (unitedwaytarrant.org); full list via 1-855-937-2372[1][3][5][7]"]
  },
  "official_source": "https://www.hhs.texas.gov (Texas Health and Human Services Commission oversees 28 ADRCs)[3][6]",
  "gotchas": ["Not a direct service provider—offers referrals and navigation only, not the services themselves; people may expect direct aid; 'No Wrong Door' means it's an entry point to other programs with their own eligibility (e.g., income for housing aid); must call local ADRC for region-specific help[2][3][5]", "Free info service, but referred programs may have waits, income tests, or limits[5]"],
  "data_shape_notes": "No income/asset tests for ADRC access; decentralized with 28 regional centers covering all counties; benefits are navigational/referral only, varying by local resources and referred programs"
}
